#include <bits/stdc++.h>
using namespace std;
int main(){
    int n;
    if(!(cin >> n)) return 0;
    vector<int> nums(n);
    for(int i = 0; i < n; i++) cin >> nums[i];
    struct Node {
        int val;
        Node* next;
        Node(int v) : val(v), next(nullptr) {}
    };
    Node* head = new Node(nums[0]);
    Node* curr = head;
    for(int i = 1; i < n; i++) {
        curr->next = new Node(nums[i]);
        curr = curr->next;
    }
    Node* slow = head;
    Node* fast = head;
    while(fast->next && fast->next->next) {
        slow = slow->next;
        fast = fast->next->next;
    }
    if(fast->next) {
        slow = slow->next;
    }
    cout << slow->val << endl;
    return 0;
}
